import { Router } from "express";
import { atualizarCampanha, criarCampanha, criarComentarioNaCampanha, criarInscricaoNaCampanha, definirPraiasDaCampanha, listarCampanhas, listarComentariosDaCampanha, obterCampanhaPorId, upsertRecolhaDeResiduosDaCampanhaNaPraia } from "../controllers/campaigns.controller.js";
export const rotasCampanhas = Router();
rotasCampanhas.get("/campaigns", listarCampanhas);
rotasCampanhas.get("/campaigns/:id", obterCampanhaPorId);
rotasCampanhas.post("/campaigns", criarCampanha);
rotasCampanhas.patch("/campaigns/:id", atualizarCampanha);
rotasCampanhas.put("/campaigns/:id/beaches", definirPraiasDaCampanha);
rotasCampanhas.post("/campaigns/:id/registrations", criarInscricaoNaCampanha);
rotasCampanhas.get("/campaigns/:id/comments", listarComentariosDaCampanha);
rotasCampanhas.post("/campaigns/:id/comments", criarComentarioNaCampanha);
rotasCampanhas.put("/campaigns/:campaignId/beaches/:beachId/collections", upsertRecolhaDeResiduosDaCampanhaNaPraia);
